class Solution:
    def maxAscendingSum(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            s = nums[i]
            best = max(best, s)
            j = i + 1
            while j < n and nums[j] > nums[j - 1]:
                s += nums[j]
                best = max(best, s)
                j += 1
        return best

