var maxAscendingSum = function(nums) {
    let best = nums[0], cur = nums[0];
    for (let i = 1; i < nums.length; i++) {
        if (nums[i] > nums[i - 1]) cur += nums[i];
        else cur = nums[i];
        if (cur > best) best = cur;
    }
    return best;
};
